if (ctx.Attributes == null) { ctx.Attributes = [:]; }
def op = ctx.Attributes['spark.semantic.operation'];
def shuffleClass = ctx.Attributes['spark.semantic.shuffle.classification'];

if (shuffleClass == 'shuffle_producer') {
  if (op == 'aggregation') {
    ctx.Attributes['spark.semantic.shuffle.reason'] = 'groupby';
  } else if (op == 'join') {
    ctx.Attributes['spark.semantic.shuffle.reason'] = 'join';
  } else if (ctx.Attributes['spark.stage.name'] != null && ctx.Attributes['spark.stage.name'].toString().toLowerCase().contains('sort')) {
    ctx.Attributes['spark.semantic.shuffle.reason'] = 'sort';
  } else if (ctx.Attributes['spark.stage.name'] != null && ctx.Attributes['spark.stage.name'].toString().toLowerCase().contains('repartition')) {
    ctx.Attributes['spark.semantic.shuffle.reason'] = 'repartition';
  }
} else if (shuffleClass == 'narrow_transformation') {
  ctx.Attributes['spark.semantic.shuffle.reason'] = 'none';
}

def stageName = ctx.Attributes?.get('spark.stage.name');
if (stageName == null) { return; }

if (ctx.Attributes == null) { ctx.Attributes = [:]; }
def stageNameStr = stageName.toString().toLowerCase();

if (stageNameStr.contains('wholestagedcodegen')) {
  ctx.Attributes['spark.semantic.execution.mode'] = 'codegen';
} else if (stageNameStr.contains('exchange')) {
  ctx.Attributes['spark.semantic.execution.mode'] = 'shuffle_exchange';
  if (stageNameStr.contains('hashpartitioning')) {
    ctx.Attributes['spark.semantic.partitioning.type'] = 'hash';
  } else if (stageNameStr.contains('rangepartitioning')) {
    ctx.Attributes['spark.semantic.partitioning.type'] = 'range';
  }
}

if (ctx.Attributes == null) { ctx.Attributes = [:]; }
def op = ctx.Attributes['spark.semantic.operation'];
def shuffleWrite = ctx.Attributes?.get('spark.stage.shuffle.write.bytes');
def duration = ctx.Duration;

def hints = [];

if (shuffleWrite != null && shuffleWrite > 100000000 && op == 'aggregation') {
  hints.add('High-cardinality groupBy - consider pre-aggregation');
}
if (shuffleWrite != null && shuffleWrite > 500000000 && op == 'join') {
  hints.add('Large join shuffle - consider broadcast join if one side is small');
}
if (duration != null && duration > 60000000000L) {
  long durationMs = duration / 1000000;
  hints.add('Long-running stage (' + durationMs + 'ms) - investigate task skew');
}

if (hints.size() > 0) {
  ctx.Attributes['spark.semantic.performance.hint'] = String.join('; ', hints);
}
